+// sendAlerts broadcasts alerts to subscribed clients.
+func (m *MetricsCollector) sendAlerts(taskID string, alerts []Alert) {
+	msg := AlertsMessage{
+		Type:   "alerts",
+		TaskID: taskID,
+		Alerts: alerts,
+	}
+
+	data, err := json.Marshal(msg)
+	if err != nil {
+		return
+	}
+
+	m.hub.Broadcast(taskID, data)
 }

